    std::cout << "a = " << a.asPercentage() << "%" << std::endl;
    std::cout << "b = " << b.asPercentage() << "%" << std::endl;
    std::cout << "mean = " << result.asPercentage() << "%" << std::endl;

    return 0;
}
```

